mapper.insert:
INSERT INTO inventory (
    medicine_id, batch_no, current_quantity, locked_quantity, production_date, expiry_date, last_inbound_time
) VALUES (
    #{medicineId}, #{batchNo}, #{currentQuantity}, #{lockedQuantity}, #{productionDate}, #{expiryDate}, #{lastInboundTime}
)

INSERT IGNORE INTO inventory (
    medicine_id, batch_no, current_quantity, locked_quantity, production_date, expiry_date, last_inbound_time
) VALUES (
    #{medicineId}, #{batchNo}, #{currentQuantity}, #{lockedQuantity}, #{productionDate}, #{expiryDate}, #{lastInboundTime}
)

mapper.update:
UPDATE inventory
SET
    current_quantity = #{currentQuantity},
    last_outbound_time = #{lastOutboundTime}
WHERE id = #{id}

UPDATE inventory
SET
    current_quantity = current_quantity - #{quantity},
    last_outbound_time = #{lastOutboundTime}
WHERE id = #{id}
  AND (current_quantity - locked_quantity) >= #{quantity}

UPDATE inventory
SET
    current_quantity = #{currentQuantity}
WHERE id = #{id}
